const xml = $input.first().json.data || '';
const config = $('1. Set Master Workspace Credentials').first().json;
const text = (v = '') => v.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]*>/g, '').trim();
const pick = (block, tag) => text((block.match(new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i')) || [])[1] || '');
const matches = [...xml.matchAll(/<item>([\s\S]*?)<\/item>/gi)].slice(0, 5);
return matches.map((m) => {
  const item = m[1]; const title = pick(item, 'title'); const pub = pick(item, 'pubDate'); const traffic = pick(item, 'ht:approx_traffic');
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `Google Trends: ${title}`,
      sourceUrl: `https://trends.google.com/trends/explore?q=${encodeURIComponent(title)}`,
      publishedAt: pub,
      sourceName: 'Google Trends RSS',
      sourceType: 'trend',
      content: `Trending topic: ${title}. Search traffic: ${traffic || 'Not specified'}. Source: Google Trends.`,
      automationSecret: config.automationSecret
    }
  };
});

const config = $('1. Set Master Workspace Credentials').first().json;
const items = $input.first().json.items || [];
return items.map((item) => {
  const s = item.snippet || {};
  const vId = item.id?.videoId || '';
  const title = s.title || 'Untitled Video';
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `YouTube Video: ${title}`,
      sourceUrl: vId ? `https://www.youtube.com/watch?v=${vId}` : 'https://www.youtube.com',
      publishedAt: s.publishedAt || new Date().toISOString(),
      sourceName: 'YouTube Data API',
      sourceType: 'media',
      content: `YouTube video for query '${config.researchQuery}'. Title: ${title}. Channel: ${s.channelTitle || 'Unknown'}. Description: ${s.description || 'N/A'}`,
      automationSecret: config.automationSecret
    }
  };
});

const config = $('1. Set Master Workspace Credentials').first().json;
const articles = $input.first().json.articles || [];
return articles.slice(0, 5).map((art) => ({
  json: {
    workspaceId: config.workspaceId,
    title: `GDELT News: ${art.title}`,
    sourceUrl: art.url,
    publishedAt: art.seendate ? `${art.seendate.slice(0,4)}-${art.seendate.slice(4,6)}-${art.seendate.slice(6,8)}T00:00:00Z` : new Date().toISOString(),
    sourceName: 'GDELT DOC API',
    sourceType: 'report',
    content: `Industry news article for query '${config.researchQuery}'. Title: ${art.title}. Outlet: ${art.domain || 'Unknown'}. URL: ${art.url}`,
    automationSecret: config.automationSecret
  }
}));

const config = $('1. Set Master Workspace Credentials').first().json;
const items = $input.first().json.items || [];
if (!items.length) return [];
const views = items.map((i) => Number(i.views || 0));
const avg = views.reduce((a, b) => a + b, 0) / views.length;
return [{
  json: {
    workspaceId: config.workspaceId,
    title: `Wikimedia Attention: ${config.researchQuery}`,
    sourceUrl: `https://en.wikipedia.org/wiki/${encodeURIComponent(config.researchQuery.replaceAll(' ', '_'))}`,
    publishedAt: new Date().toISOString(),
    sourceName: 'Wikimedia Pageviews API',
    sourceType: 'report',
    content: `Wikimedia attention proxy for '${config.researchQuery}'. 30-day average daily views: ${avg.toFixed(0)}.`,
    automationSecret: config.automationSecret
  }
}];
